INSERT INTO `mail_templates` (`id`, `mongo_id`, `updatedAt`, `comment`, `title`, `subTitle`, `content`, `type`, `createdAt`) VALUES (1,'YsV4XjTM','2025-11-22 06:37:48','找回密码','通过加密链接重置密码','找回密码','<h2><strong>重置密码</strong></h2><p>您好，{{email}}：</p><p>请点击下方链接重置您的密码：</p><p><a href=\"{{siteDomain}}/user-center/reset-password?key={{token}}\" target=\"\"><br> &nbsp; &nbsp; &nbsp; &nbsp;<span style=\"color: rgb(225, 60, 57);\">点击重置密码</span><br> &nbsp; &nbsp; &nbsp;</a></p><p>如果无法点击，请将链接复制到浏览器打开：</p><p><br> &nbsp; &nbsp; &nbsp;{{siteDomain}}/user-center/reset-password?key={{token}}<br> &nbsp; &nbsp;</p><p><br> &nbsp; &nbsp; &nbsp;&copy; 2025-present {{siteDomain}} All rights reserved.<br> &nbsp; &nbsp;</p>','password_reset','2025-08-05 14:51:58');
INSERT INTO `mail_templates` (`id`, `mongo_id`, `updatedAt`, `comment`, `title`, `subTitle`, `content`, `type`, `createdAt`) VALUES (2,'sdQ6Etje','2025-11-22 06:38:23','留言通知','有人给您留言啦！！！','留言通知','<p><strong>留言通知</strong></p><h2>您有新的留言回复</h2><p><strong>{{message_author_userName}}</strong> 于 <strong>{{message_sendDate}}</strong><br> &nbsp; &nbsp; &nbsp;在文章「<strong>{{message_content_title}}</strong>」中回复了您。<br> &nbsp; &nbsp;</p><p>感谢您的参与，欢迎继续交流。</p><p><br> &nbsp; &nbsp; &nbsp;&copy; 2025-present {{siteDomain}} All rights reserved.<br> &nbsp; &nbsp;</p>','reminder','2025-08-05 14:51:58');
INSERT INTO `mail_templates` (`id`, `mongo_id`, `updatedAt`, `comment`, `title`, `subTitle`, `content`, `type`, `createdAt`) VALUES (3,'ySLB1ojJ','2025-11-22 06:39:48','邮箱验证码','请查收您的邮箱验证码','发送验证码','<p><strong>邮箱验证码</strong></p><p>您正在注册 <span style=\"color: rgb(225, 60, 57);\"><strong>{{siteName}}</strong></span> 账号。</p><p><br> &nbsp; &nbsp; &nbsp;本次验证码为：<span style=\"color: rgb(225, 60, 57);\"><strong>{{msgCode}}</strong></span></p><p>验证码有效期内请勿泄露，如非本人操作请忽略本邮件。</p><p><br> &nbsp; &nbsp; &nbsp;&copy; 2025-present {{siteDomain}} All rights reserved.<br> &nbsp; &nbsp;</p>','verification','2025-08-05 14:51:58');
INSERT INTO `menus` (`id`, `menuType`, `menuName`, `routeName`, `routePath`, `component`, `i18nKey`, `icon`, `iconType`, `parentId`, `status`, `keepAlive`, `constant`, `order`, `href`, `hideInMenu`, `activeMenu`, `multiTab`, `fixedIndexInTab`, `query`, `buttons`, `createBy`, `updateBy`, `updatedAt`, `createdAt`) VALUES (1,'2','首页','home','/home','layout.base$view.home','route.home','mdi:monitor-dashboard','1',0,'1',0,0,0,NULL,0,NULL,0,NULL,'[]','[{\"desc\":\"获取 Sitemap 状态\",\"api\":\"v1/sitemap/status\",\"permissionCode\":\"sitemap.status\",\"httpMethod\":\"GET\"},{\"desc\":\"刷新 Sitemap\",\"api\":\"v1/sitemap/refresh\",\"permissionCode\":\"sitemap.refresh\",\"httpMethod\":\"POST\"},{\"desc\":\"清空 Sitemap 缓存\",\"api\":\"v1/sitemap/cache\",\"permissionCode\":\"sitemap.cache\",\"httpMethod\":\"DELETE\"},{\"desc\":\"预览 Sitemap\",\"api\":\"v1/sitemap/preview\",\"permissionCode\":\"sitemap.preview\",\"httpMethod\":\"GET\"},{\"desc\":\"获取 Sitemap 配置\",\"api\":\"v1/sitemap/config\",\"permissionCode\":\"sitemap.config\",\"httpMethod\":\"GET\"},{\"desc\":\"更新 Sitemap 配置\",\"api\":\"v1/sitemap/config\",\"permissionCode\":\"sitemap.configPut\",\"httpMethod\":\"PUT\"},{\"desc\":\"测试 Sitemap 访问\",\"api\":\"v1/sitemap/test\",\"permissionCode\":\"sitemap.test\",\"httpMethod\":\"GET\"}]',NULL,NULL,'2025-12-25 22:52:26','2025-08-05 14:51:59');
